import { useState, useEffect, useRef } from "react";

const CATS = ["Todo", "Remeras", "Pantalones", "Camperas", "Vestidos", "Calzado", "Accesorios", "Otros"];
const STORAGE_KEY = "prendas-tienda";
const WA_NUMBER = "5491164912738"; // número correcto sin +
const LOGO = "data:image/png;base64,";

const GS = `@import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=DM+Sans:wght@400;500&display=swap');`;

// Hero background image
const BG_IMAGE = "data:image/jpeg;base64,";

const LINEN = {
  backgroundColor: "#ede6d9",
  backgroundImage: `url("${BG_IMAGE}")`,
  backgroundSize: "contain",
  backgroundPosition: "center center",
  backgroundAttachment: "fixed",
  backgroundRepeat: "no-repeat",
};

// Floating decorative clothing SVGs
const ICONS = [
  // Hanger
  `<svg viewBox="0 0 48 48" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M24 8a4 4 0 1 1 0 8" stroke="%238b5e3c" stroke-width="2.5" stroke-linecap="round"/><path d="M24 16S6 26 6 34h36c0-8-18-18-18-18z" stroke="%238b5e3c" stroke-width="2.5" stroke-linejoin="round"/></svg>`,
  // T-shirt
  `<svg viewBox="0 0 48 48" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M6 12l8-5h5a5 5 0 0 0 10 0h5l8 5-5 7-5-2v22H14V17l-5 2-3-7z" stroke="%238b5e3c" stroke-width="2.5" stroke-linejoin="round"/></svg>`,
  // Dress
  `<svg viewBox="0 0 48 48" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M17 5h14l2 10-9 5-9-5 2-10z" stroke="%238b5e3c" stroke-width="2.5" stroke-linejoin="round"/><path d="M9 20l8-5 7 5 7-5 8 5-5 22H14L9 20z" stroke="%238b5e3c" stroke-width="2.5" stroke-linejoin="round"/></svg>`,
  // Pants
  `<svg viewBox="0 0 48 48" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M9 9h30l-5 26-10-5-10 5L9 9z" stroke="%238b5e3c" stroke-width="2.5" stroke-linejoin="round"/><line x1="24" y1="9" x2="24" y2="25" stroke="%238b5e3c" stroke-width="2.5" stroke-linecap="round"/></svg>`,
  // Jacket
  `<svg viewBox="0 0 48 48" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M6 14l9-6 4 5a5 5 0 0 0 10 0l4-5 9 6-4 8-6-3v22H10V19l-6 3-4-8z" stroke="%238b5e3c" stroke-width="2.5" stroke-linejoin="round"/><line x1="24" y1="19" x2="24" y2="41" stroke="%238b5e3c" stroke-width="2" stroke-linecap="round" stroke-dasharray="3 3"/></svg>`,
  // Shoe
  `<svg viewBox="0 0 48 48" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M4 32c0 0 4-14 14-14l14 4 8 2v6H4v-4z" stroke="%238b5e3c" stroke-width="2.5" stroke-linejoin="round"/><path d="M4 36h38" stroke="%238b5e3c" stroke-width="2.5" stroke-linecap="round"/></svg>`,
];

const DECOS = [
  { x: "2%",  y: "5%",   rot: -18, op: 0.13, s: 1.1, icon: 0 },
  { x: "87%", y: "2%",   rot:  14, op: 0.11, s: 0.9, icon: 1 },
  { x: "91%", y: "22%",  rot: -10, op: 0.10, s: 1.2, icon: 2 },
  { x: "1%",  y: "32%",  rot:  20, op: 0.12, s: 0.85,icon: 3 },
  { x: "89%", y: "50%",  rot: -22, op: 0.10, s: 1.0, icon: 4 },
  { x: "3%",  y: "60%",  rot:  12, op: 0.12, s: 0.95,icon: 5 },
  { x: "86%", y: "74%",  rot: -15, op: 0.11, s: 1.1, icon: 0 },
  { x: "2%",  y: "82%",  rot:  25, op: 0.10, s: 0.9, icon: 2 },
  { x: "88%", y: "90%",  rot: -8,  op: 0.10, s: 1.0, icon: 1 },
  { x: "50%", y: "1%",   rot:  5,  op: 0.09, s: 0.8, icon: 3 },
  { x: "45%", y: "97%",  rot: -5,  op: 0.09, s: 0.85,icon: 4 },
];

function BgDeco() {
  return (
    <div style={{ position: "fixed", inset: 0, pointerEvents: "none", zIndex: 0, overflow: "hidden" }}>
      {DECOS.map((d, i) => (
        <div key={i} style={{ position: "absolute", left: d.x, top: d.y, width: 64, height: 64, opacity: d.op, transform: `rotate(${d.rot}deg) scale(${d.s})` }}
          dangerouslySetInnerHTML={{ __html: ICONS[d.icon] }} />
      ))}
    </div>
  );
}

function compress(file, cb) {
  const reader = new FileReader();
  reader.onload = e => {
    const img = new Image();
    img.onload = () => {
      const canvas = document.createElement("canvas");
      const MAX = 600;
      let w = img.width, h = img.height;
      if (w > h && w > MAX) { h = h * MAX / w; w = MAX; }
      else if (h > MAX) { w = w * MAX / h; h = MAX; }
      canvas.width = w; canvas.height = h;
      canvas.getContext("2d").drawImage(img, 0, 0, w, h);
      cb(canvas.toDataURL("image/jpeg", 0.75));
    };
    img.src = e.target.result;
  };
  reader.readAsDataURL(file);
}

function CartDrawer({ cart, onClose, onRemove, onClear }) {
  const total = cart.reduce((s, i) => s + i.precio, 0);
  function sendToWA() {
    if (!cart.length) return;
    const lines = cart.map((p, i) => `${i + 1}. ${p.nombre} - $${p.precio.toLocaleString("es-AR")}`).join("\n");
    const msg = `Hola! Me interesan estas prendas de *Entre Perchas* 👗 🛍️\n\n${lines}\n\n*Total: $${total.toLocaleString("es-AR")}*\n\n¿Están disponibles?`;
    window.open(`https://wa.me/${WA_NUMBER}?text=${encodeURIComponent(msg)}`, "_blank");
  }
  return (
    <div style={{ position: "fixed", inset: 0, zIndex: 100, display: "flex" }}>
      <div onClick={onClose} style={{ flex: 1, background: "#1c1a1670" }} />
      <div style={{ width: 340, maxWidth: "92vw", background: "#faf8f4", display: "flex", flexDirection: "column", boxShadow: "-4px 0 32px #1c1a1630" }}>
        <div style={{ background: "#1c1a16", padding: "1.2rem 1.4rem", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <span style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 22, color: "#faf8f4", letterSpacing: 2 }}>MI CARRITO</span>
          <button onClick={onClose} style={{ background: "none", border: "none", color: "#a89070", fontSize: 22, cursor: "pointer", lineHeight: 1 }}>✕</button>
        </div>
        <div style={{ flex: 1, overflowY: "auto", padding: "1rem 1.2rem" }}>
          {cart.length === 0 && (
            <div style={{ textAlign: "center", padding: "3rem 0", color: "#a89070" }}>
              <div style={{ fontSize: 36, marginBottom: 10 }}>🛍️</div>
              <div style={{ fontSize: 14 }}>Tu carrito está vacío</div>
            </div>
          )}
          {cart.map((p, i) => (
            <div key={i} style={{ display: "flex", gap: 12, alignItems: "center", marginBottom: 12, background: "#fff", borderRadius: 12, border: "1px solid #e8ddd0", padding: "0.7rem 0.9rem" }}>
              <img src={p.foto} alt={p.nombre} style={{ width: 52, height: 52, objectFit: "cover", borderRadius: 8, flexShrink: 0 }} />
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontSize: 13, fontWeight: 500, color: "#1c1a16", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{p.nombre}</div>
                <div style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 18, color: "#c8762a" }}>${p.precio.toLocaleString("es-AR")}</div>
              </div>
              <button onClick={() => onRemove(i)} style={{ background: "#fcebeb", border: "none", borderRadius: 8, padding: "5px 10px", color: "#a32d2d", fontSize: 12, cursor: "pointer", flexShrink: 0 }}>✕</button>
            </div>
          ))}
        </div>
        {cart.length > 0 && (
          <div style={{ padding: "1rem 1.2rem", borderTop: "1px solid #e8ddd0" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
              <span style={{ fontSize: 14, color: "#6b5b47", fontWeight: 500 }}>Total ({cart.length} {cart.length === 1 ? "prenda" : "prendas"})</span>
              <span style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 26, color: "#1c1a16" }}>${total.toLocaleString("es-AR")}</span>
            </div>
            <button onClick={sendToWA} style={{ width: "100%", background: "#25D366", color: "#fff", border: "none", borderRadius: 10, padding: "14px", fontSize: 15, fontWeight: 500, cursor: "pointer", marginBottom: 8 }}>
              💬 Enviar pedido por WhatsApp
            </button>
            <button onClick={onClear} style={{ width: "100%", background: "none", border: "1px solid #c9b89a", borderRadius: 10, padding: "10px", fontSize: 13, color: "#8b7355", cursor: "pointer" }}>
              Vaciar carrito
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

export default function App() {
  const [view, setView] = useState("shop");
  const [prendas, setPrendas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [catFilter, setCatFilter] = useState("Todo");
  const [detail, setDetail] = useState(null);
  const [cart, setCart] = useState([]);
  const [cartOpen, setCartOpen] = useState(false);
  const [addedId, setAddedId] = useState(null);
  const [adminPass, setAdminPass] = useState("");
  const [adminOk, setAdminOk] = useState(false);
  const [passErr, setPassErr] = useState(false);
  const [form, setForm] = useState({ nombre: "", desc: "", cat: "Remeras", precio: "", foto: null, preview: null });
  const [saving, setSaving] = useState(false);
  const [saved, setSaved] = useState(false);
  const [deleting, setDeleting] = useState(null);
  const fileRef = useRef();
  const PASS = "Octi2023";

  useEffect(() => {
    (async () => {
      try {
        const res = await window.storage.get(STORAGE_KEY, true);
        if (res) setPrendas(JSON.parse(res.value));
      } catch (_) {}
      setLoading(false);
    })();
  }, []);

  async function savePrendas(list) {
    try { await window.storage.set(STORAGE_KEY, JSON.stringify(list), true); } catch (_) {}
    setPrendas(list);
  }

  function handleFile(e) {
    const file = e.target.files[0];
    if (!file) return;
    compress(file, preview => setForm(f => ({ ...f, foto: preview, preview })));
  }

  async function handleAdd(e) {
    e.preventDefault();
    if (!form.nombre || !form.precio || !form.foto) return;
    setSaving(true);
    const nueva = { id: Date.now(), nombre: form.nombre, desc: form.desc, cat: form.cat, precio: Number(form.precio), foto: form.foto, fecha: new Date().toLocaleDateString("es-AR") };
    await savePrendas([nueva, ...prendas]);
    setForm({ nombre: "", desc: "", cat: "Remeras", precio: "", foto: null, preview: null });
    if (fileRef.current) fileRef.current.value = "";
    setSaving(false); setSaved(true);
    setTimeout(() => setSaved(false), 2500);
  }

  async function handleDelete(id) {
    setDeleting(id);
    await savePrendas(prendas.filter(p => p.id !== id));
    setDeleting(null);
  }

  function addToCart(p) {
    setCart(c => [...c, p]);
    setAddedId(p.id);
    setTimeout(() => setAddedId(null), 1000);
  }

  const filtered = prendas.filter(p => {
    const matchCat = catFilter === "Todo" || p.cat === catFilter;
    const matchSearch = !search || p.nombre.toLowerCase().includes(search.toLowerCase()) || p.desc?.toLowerCase().includes(search.toLowerCase()) || p.cat.toLowerCase().includes(search.toLowerCase());
    return matchCat && matchSearch;
  });

  // DETAIL
  if (detail) return (
    <div style={{ minHeight: "100vh", fontFamily: "'DM Sans', sans-serif", position: "relative", ...LINEN }}>
      <style>{GS}</style>
      <div style={{ position: "fixed", inset: 0, background: "rgba(255,250,244,0.55)", zIndex: 0, pointerEvents: "none" }} />
      {cartOpen && <CartDrawer cart={cart} onClose={() => setCartOpen(false)} onRemove={i => setCart(c => c.filter((_, idx) => idx !== i))} onClear={() => setCart([])} />}
      <div style={{ background: "#1c1a16", padding: "1rem 1.4rem", display: "flex", alignItems: "center", justifyContent: "space-between", position: "sticky", top: 0, zIndex: 10 }}>
        <button onClick={() => setDetail(null)} style={{ background: "none", border: "none", color: "#d4a84b", fontSize: 14, cursor: "pointer", fontFamily: "'DM Sans', sans-serif" }}>← Volver</button>
        <button onClick={() => setCartOpen(true)} style={{ background: cart.length ? "#c8762a" : "transparent", border: "1px solid #a89070", borderRadius: 8, padding: "7px 14px", color: cart.length ? "#fff" : "#d4a84b", fontSize: 13, cursor: "pointer", fontWeight: 500 }}>
          🛍️{cart.length > 0 ? ` ${cart.length}` : ""}
        </button>
      </div>
      <div style={{ maxWidth: 520, margin: "0 auto", padding: "1.5rem 1rem 3rem", position: "relative", zIndex: 1 }}>
        <div style={{ background: "rgba(255,252,247,0.96)", borderRadius: 16, overflow: "hidden", border: "1px solid #e8ddd0", boxShadow: "0 4px 24px #1c1a1612" }}>
          <img src={detail.foto} alt={detail.nombre} style={{ width: "100%", height: 380, objectFit: "cover" }} />
          <div style={{ padding: "1.5rem" }}>
            <span style={{ background: "#f0e8da", color: "#8b5e3c", fontSize: 11, fontWeight: 500, padding: "4px 12px", borderRadius: 20, textTransform: "uppercase", letterSpacing: "0.08em" }}>{detail.cat}</span>
            <h2 style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 36, margin: "0.6rem 0 0.3rem", color: "#1c1a16", letterSpacing: 1 }}>{detail.nombre}</h2>
            <p style={{ fontSize: 28, fontFamily: "'Bebas Neue', sans-serif", color: "#c8762a", margin: "0 0 1rem" }}>${detail.precio.toLocaleString("es-AR")}</p>
            {detail.desc && <p style={{ fontSize: 14, color: "#6b5b47", lineHeight: 1.7, marginBottom: "1.5rem" }}>{detail.desc}</p>}
            <button onClick={() => { addToCart(detail); setDetail(null); setCartOpen(true); }}
              style={{ display: "block", width: "100%", background: "#1c1a16", color: "#faf8f4", border: "none", borderRadius: 10, padding: "14px", fontSize: 15, fontWeight: 500, cursor: "pointer", marginBottom: 10 }}>
              🛍️ Agregar al carrito
            </button>
            <a href={`https://wa.me/${WA_NUMBER}?text=${encodeURIComponent(`Hola! Me interesa esta prenda de Entre Perchas: ${detail.nombre} - $${detail.precio}`)}`} target="_blank" rel="noreferrer"
              style={{ display: "block", background: "#25D366", color: "#fff", textAlign: "center", padding: "14px", borderRadius: 10, fontWeight: 500, fontSize: 15, textDecoration: "none" }}>
              💬 Consultar solo esta prenda
            </a>
          </div>
        </div>
      </div>
    </div>
  );

  // ADMIN LOGIN
  if (view === "admin" && !adminOk) return (
    <div style={{ minHeight: "100vh", background: "#1c1a16", display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "'DM Sans', sans-serif" }}>
      <style>{GS}</style>
      <div style={{ background: "#faf8f4", borderRadius: 16, padding: "2.5rem", width: "100%", maxWidth: 360, textAlign: "center" }}>
        <div style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 28, letterSpacing: 2, marginBottom: "0.2rem", color: "#1c1a16" }}>PANEL ADMIN</div>
        <div style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 15, color: "#c8762a", letterSpacing: 3, marginBottom: "1.4rem" }}>ENTRE PERCHAS</div>
        <input type="password" placeholder="Contraseña" value={adminPass}
          onChange={e => { setAdminPass(e.target.value); setPassErr(false); }}
          onKeyDown={e => e.key === "Enter" && (adminPass === PASS ? (setAdminOk(true), setPassErr(false)) : setPassErr(true))}
          style={{ width: "100%", padding: "12px 14px", borderRadius: 10, border: passErr ? "1.5px solid #e24b4a" : "1px solid #c9b89a", fontSize: 15, marginBottom: 8, boxSizing: "border-box", outline: "none" }} />
        {passErr && <p style={{ color: "#e24b4a", fontSize: 12, margin: "0 0 8px" }}>Contraseña incorrecta</p>}
        <button onClick={() => adminPass === PASS ? (setAdminOk(true), setPassErr(false)) : setPassErr(true)}
          style={{ width: "100%", background: "#1c1a16", color: "#faf8f4", border: "none", borderRadius: 10, padding: 14, fontSize: 15, cursor: "pointer", fontWeight: 500 }}>
          Entrar
        </button>
        <button onClick={() => { setView("shop"); setAdminPass(""); setPassErr(false); }} style={{ marginTop: 12, background: "none", border: "none", color: "#8b7355", fontSize: 13, cursor: "pointer" }}>← Volver a la tienda</button>
        <p style={{ fontSize: 11, color: "#c9b89a", marginTop: "1.2rem" }}>Contraseña por defecto: admin123</p>
      </div>
    </div>
  );

  // ADMIN PANEL
  if (view === "admin" && adminOk) return (
    <div style={{ minHeight: "100vh", background: "#faf8f4", fontFamily: "'DM Sans', sans-serif" }}>
      <style>{GS}</style>
      <div style={{ background: "#1c1a16", padding: "1rem 1.5rem", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <img src={LOGO} alt="Entre Perchas" style={{ height: 36, width: 36, objectFit: "contain", borderRadius: "50%", background: "#fff", padding: 2 }} />
          <div>
            <span style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 20, color: "#faf8f4", letterSpacing: 2 }}>ADMIN </span>
            <span style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 14, color: "#c8762a", letterSpacing: 2 }}>· ENTRE PERCHAS</span>
          </div>
        </div>
        <button onClick={() => { setView("shop"); setAdminOk(false); setAdminPass(""); }} style={{ background: "#d4a84b", border: "none", borderRadius: 8, padding: "7px 16px", fontSize: 13, cursor: "pointer", fontWeight: 500 }}>Ver tienda</button>
      </div>
      <div style={{ maxWidth: 640, margin: "0 auto", padding: "2rem 1rem" }}>
        <div style={{ background: "#fff", borderRadius: 14, border: "1px solid #e8ddd0", padding: "1.5rem", marginBottom: "2rem" }}>
          <h3 style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 22, letterSpacing: 1, marginTop: 0, marginBottom: "1.2rem", color: "#1c1a16" }}>AGREGAR PRENDA</h3>
          <form onSubmit={handleAdd} style={{ display: "flex", flexDirection: "column", gap: 14 }}>
            <input required placeholder="Nombre de la prenda" value={form.nombre} onChange={e => setForm(f => ({ ...f, nombre: e.target.value }))}
              style={{ padding: "11px 14px", borderRadius: 10, border: "1px solid #c9b89a", fontSize: 14, outline: "none" }} />
            <textarea placeholder="Descripción (talle, estado, marca...)" value={form.desc} onChange={e => setForm(f => ({ ...f, desc: e.target.value }))}
              rows={3} style={{ padding: "11px 14px", borderRadius: 10, border: "1px solid #c9b89a", fontSize: 14, resize: "vertical", outline: "none", fontFamily: "inherit" }} />
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
              <select value={form.cat} onChange={e => setForm(f => ({ ...f, cat: e.target.value }))}
                style={{ padding: "11px 14px", borderRadius: 10, border: "1px solid #c9b89a", fontSize: 14, background: "#fff", outline: "none" }}>
                {CATS.filter(c => c !== "Todo").map(c => <option key={c}>{c}</option>)}
              </select>
              <input required type="number" placeholder="Precio ($)" value={form.precio} onChange={e => setForm(f => ({ ...f, precio: e.target.value }))} min={1}
                style={{ padding: "11px 14px", borderRadius: 10, border: "1px solid #c9b89a", fontSize: 14, outline: "none" }} />
            </div>
            <div style={{ border: "2px dashed #c9b89a", borderRadius: 12, padding: "1.5rem", textAlign: "center", cursor: "pointer", background: form.preview ? "#fff" : "#faf8f4" }}
              onClick={() => fileRef.current.click()}>
              {form.preview
                ? <img src={form.preview} alt="preview" style={{ maxHeight: 180, borderRadius: 8, maxWidth: "100%", objectFit: "contain" }} />
                : <div style={{ color: "#a89070", fontSize: 14 }}>📷 Tocá para subir foto</div>}
            </div>
            <input ref={fileRef} type="file" accept="image/*" style={{ display: "none" }} onChange={handleFile} />
            <button type="submit" disabled={saving || !form.foto}
              style={{ background: saving ? "#a89070" : "#1c1a16", color: "#faf8f4", border: "none", borderRadius: 10, padding: 14, fontSize: 15, cursor: saving ? "not-allowed" : "pointer", fontWeight: 500 }}>
              {saving ? "Guardando..." : saved ? "✓ ¡Prenda guardada!" : "Agregar prenda"}
            </button>
          </form>
        </div>
        <h3 style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 20, letterSpacing: 1, color: "#1c1a16", marginBottom: "1rem" }}>PRENDAS CARGADAS ({prendas.length})</h3>
        {prendas.length === 0 && <p style={{ color: "#a89070", fontSize: 14 }}>Todavía no cargaste ninguna prenda.</p>}
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {prendas.map(p => (
            <div key={p.id} style={{ background: "#fff", borderRadius: 12, border: "1px solid #e8ddd0", display: "flex", alignItems: "center", gap: 14, padding: "0.8rem 1rem" }}>
              <img src={p.foto} alt={p.nombre} style={{ width: 60, height: 60, objectFit: "cover", borderRadius: 8, flexShrink: 0 }} />
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontWeight: 500, fontSize: 14, color: "#1c1a16", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{p.nombre}</div>
                <div style={{ fontSize: 12, color: "#a89070" }}>{p.cat} · ${p.precio.toLocaleString("es-AR")} · {p.fecha}</div>
              </div>
              <button onClick={() => handleDelete(p.id)} disabled={deleting === p.id}
                style={{ background: "#fcebeb", border: "none", borderRadius: 8, padding: "7px 12px", color: "#a32d2d", fontSize: 12, cursor: "pointer", fontWeight: 500, flexShrink: 0 }}>
                {deleting === p.id ? "..." : "Eliminar"}
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );

  // SHOP
  return (
    <div style={{ minHeight: "100vh", fontFamily: "'DM Sans', sans-serif", position: "relative", ...LINEN }}>
      <style>{`
        ${GS}
        .card-item { transition: transform 0.18s, box-shadow 0.18s; }
        .card-item:hover { transform: translateY(-4px); box-shadow: 0 10px 28px #1c1a1618; }
        .cat-btn { transition: all 0.15s; }
        .cat-btn:hover { background: #e0d4c0 !important; }
        .add-btn { transition: background 0.15s, transform 0.1s; }
        .add-btn:hover { background: #c8762a !important; }
        .add-btn:active { transform: scale(0.96); }
      `}</style>

      {/* white overlay for readability */}
      <div style={{ position: "fixed", inset: 0, background: "rgba(255,250,244,0.55)", zIndex: 0, pointerEvents: "none" }} />
      {cartOpen && <CartDrawer cart={cart} onClose={() => setCartOpen(false)} onRemove={i => setCart(c => c.filter((_, idx) => idx !== i))} onClear={() => setCart([])} />}

      {/* HEADER */}
      <div style={{ background: "#1c1a16", padding: "1rem 1.5rem", display: "flex", alignItems: "center", justifyContent: "space-between", position: "sticky", top: 0, zIndex: 10 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <img src={LOGO} alt="Entre Perchas" style={{ height: 48, width: 48, objectFit: "contain", borderRadius: "50%", background: "#fff", padding: 2 }} />
          <div>
            <div style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 22, color: "#faf8f4", letterSpacing: 2, lineHeight: 1 }}>ENTRE PERCHAS</div>
            <div style={{ fontSize: 10, color: "#a89070", letterSpacing: "0.08em", textTransform: "uppercase" }}>Moda circular · historias que continúan</div>
          </div>
        </div>
        <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
          <button onClick={() => setCartOpen(true)}
            style={{ background: cart.length ? "#c8762a" : "transparent", border: "1px solid #a89070", borderRadius: 8, padding: "7px 14px", color: cart.length ? "#fff" : "#d4a84b", fontSize: 13, cursor: "pointer", fontWeight: 500, transition: "all 0.2s" }}>
            🛍️{cart.length > 0 ? ` ${cart.length}` : ""}
          </button>
          <button onClick={() => setView("admin")} style={{ background: "transparent", border: "1px solid #a89070", borderRadius: 8, padding: "7px 14px", color: "#d4a84b", fontSize: 12, cursor: "pointer", fontWeight: 500 }}>
            Admin ↗
          </button>
        </div>
      </div>

      {/* HERO STRIP */}
      <div style={{ background: "#d4a84b", padding: "0.8rem 1.5rem", textAlign: "center" }}>
        <span style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 17, letterSpacing: 2, color: "#1c1a16" }}>✦ PRENDAS ÚNICAS A PRECIOS ACCESIBLES ✦</span>
      </div>

      {/* SEARCH + FILTERS */}
      <div style={{ maxWidth: 960, margin: "0 auto", padding: "1.5rem 1rem 0.5rem", position: "relative", zIndex: 1 }}>
        <input type="search" placeholder="Buscar prenda..." value={search} onChange={e => setSearch(e.target.value)}
          style={{ width: "100%", boxSizing: "border-box", padding: "13px 18px", borderRadius: 12, border: "1.5px solid #c9b89a", fontSize: 15, marginBottom: "1rem", outline: "none", background: "rgba(255,252,247,0.95)" }} />
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: "1.5rem" }}>
          {CATS.map(c => (
            <button key={c} className="cat-btn" onClick={() => setCatFilter(c)}
              style={{ padding: "7px 16px", borderRadius: 20, border: "1px solid #c9b89a", fontSize: 13, cursor: "pointer", fontWeight: 500, background: catFilter === c ? "#1c1a16" : "rgba(255,252,247,0.9)", color: catFilter === c ? "#faf8f4" : "#4a3728" }}>
              {c}
            </button>
          ))}
        </div>
      </div>

      {/* GRID */}
      <div style={{ maxWidth: 960, margin: "0 auto", padding: "0 1rem 3rem", position: "relative", zIndex: 1 }}>
        {loading && <p style={{ color: "#a89070", textAlign: "center", padding: "3rem 0" }}>Cargando...</p>}
        {!loading && filtered.length === 0 && (
          <div style={{ textAlign: "center", padding: "4rem 0", color: "#8b7355" }}>
            <div style={{ fontSize: 40, marginBottom: 12 }}>🧥</div>
            <div style={{ fontSize: 15 }}>{prendas.length === 0 ? "Todavía no hay prendas cargadas." : "No encontramos resultados."}</div>
          </div>
        )}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(210px, 1fr))", gap: 16 }}>
          {filtered.map(p => (
            <div key={p.id} className="card-item" style={{ background: "rgba(255,252,247,0.97)", borderRadius: 14, overflow: "hidden", border: "1px solid #e0d0bc", display: "flex", flexDirection: "column" }}>
              <div style={{ position: "relative", cursor: "pointer" }} onClick={() => setDetail(p)}>
                <img src={p.foto} alt={p.nombre} style={{ width: "100%", height: 230, objectFit: "cover", display: "block" }} />
                <span style={{ position: "absolute", top: 10, left: 10, background: "#f0e8da", color: "#8b5e3c", fontSize: 10, fontWeight: 500, padding: "3px 10px", borderRadius: 20, textTransform: "uppercase", letterSpacing: "0.08em" }}>{p.cat}</span>
                {addedId === p.id && (
                  <div style={{ position: "absolute", inset: 0, background: "#1c1a16cc", display: "flex", alignItems: "center", justifyContent: "center" }}>
                    <span style={{ color: "#d4a84b", fontFamily: "'Bebas Neue', sans-serif", fontSize: 22, letterSpacing: 2 }}>✓ AGREGADO</span>
                  </div>
                )}
              </div>
              <div style={{ padding: "0.9rem 1rem", flex: 1, display: "flex", flexDirection: "column" }}>
                <div onClick={() => setDetail(p)} style={{ cursor: "pointer", fontWeight: 500, fontSize: 14, color: "#1c1a16", marginBottom: 3, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{p.nombre}</div>
                <div onClick={() => setDetail(p)} style={{ cursor: "pointer", fontFamily: "'Bebas Neue', sans-serif", fontSize: 22, color: "#c8762a", marginBottom: 10 }}>${p.precio.toLocaleString("es-AR")}</div>
                <button className="add-btn" onClick={() => addToCart(p)}
                  style={{ marginTop: "auto", background: "#1c1a16", color: "#faf8f4", border: "none", borderRadius: 8, padding: "9px", fontSize: 13, cursor: "pointer", fontWeight: 500, width: "100%" }}>
                  + Agregar al carrito
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* FOOTER */}
      <div style={{ background: "#1c1a16", padding: "1.8rem 1.5rem", textAlign: "center", position: "relative", zIndex: 1 }}>
        <div style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 22, color: "#d4a84b", letterSpacing: 3, marginBottom: 6 }}>ENTRE PERCHAS</div>
        <div style={{ fontSize: 12, color: "#6b5b47" }}>Moda circular, historias que continúan ✦ Consultanos por WhatsApp</div>
      </div>
    </div>
  );
}
